/**
 * generate-api-data.ts — Build-time code generator for Lurek2D VS Code extension.
 *
 * Reads data/lurek-api.json (generated by python tools/docs/gen_extension_api.py)
 * and emits src/generated/lurekApiData.ts with the API data baked in as a
 * TypeScript constant.  This runs once at npm-build time; no JSON reading at
 * VS Code startup.
 *
 * Usage:
 *   npx tsx tools/generate-api-data.ts
 */

import * as fs from "fs";
import * as path from "path";
import { fileURLToPath } from "url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const root = path.resolve(__dirname, "..");

const inputPath = path.join(root, "data", "lurek-api.json");
const outputPath = path.join(root, "src", "generated", "lurekApiData.ts");

if (!fs.existsSync(inputPath)) {
  console.error(
    `ERROR: ${inputPath} not found.\n` +
      `Run first: python tools/docs/gen_extension_api.py\n` +
      `  --input  logs/data/lua_api_data.json\n` +
      `  --output extensions/vscode/data/lurek-api.json`,
  );
  process.exit(1);
}

const raw = fs.readFileSync(inputPath, "utf-8");

// Validate JSON before generating
let data: Record<string, unknown>;
try {
  data = JSON.parse(raw);
} catch (err) {
  console.error(`ERROR: Failed to parse ${inputPath}: ${err}`);
  process.exit(1);
}

const callbacks = Array.isArray(data.callbacks)
  ? (data.callbacks as Array<{ name: string }>)
  : [];
const callbackNames = callbacks.map((cb) => cb.name);
const modules = Array.isArray(data.modules)
  ? (data.modules as Array<{ name: string }>)
  : [];

// Inline the full JSON as a TypeScript constant — esbuild bundles it into
// dist/extension.js so there are zero filesystem reads at runtime.
const generatedTs = `// AUTO-GENERATED — DO NOT EDIT
// Source: extensions/vscode/data/lurek-api.json
// Generator: extensions/vscode/tools/generate-api-data.ts
// Regenerate: npm run generate-api  (runs automatically via npm run build)
//
// To update the Lurek API data:
//   1. python tools/docs/gen_extension_api.py
//   2. npm run build  (or npm run generate-api)

/* eslint-disable */
// @ts-nocheck

/** Complete Lurek2D API data, baked in at build time. */
export const LUREK_API_DATA: Record<string, unknown> = ${JSON.stringify(data)};

/**
 * Lurek2D engine callback names, extracted at build time from lurek-api.json.
 * These are the function names that users assign to \`lurek.<name>\` in their
 * game scripts (e.g. \`function lurek.init() ... end\`).
 */
export const LUREK_CALLBACK_NAMES: ReadonlySet<string> = new Set<string>([
${callbackNames.map((n) => `  ${JSON.stringify(n)},`).join("\n")}
]);
`;

fs.mkdirSync(path.dirname(outputPath), { recursive: true });
fs.writeFileSync(outputPath, generatedTs, "utf-8");

console.log(
  `✓ Generated ${path.relative(root, outputPath)}` +
    ` — ${modules.length} modules, ${callbackNames.length} callbacks`,
);
